def max_of_three(a, b, c):
  """Returns the largest of three numbers."""
  return max(a, b, c) 
```

```python
def factorial(n):
  if n == 0:
    return 1
  else:
    return n * factorial(n-1)
```

```python
def clamp(x, lo, hi):
  return max(lo, min(x, hi)) 
```

```python
def title_case(s):
  """Converts a string to title case."""
  return s.title()
``` 


This function leverages the built-in `title()` method in Python, which directly handles the conversion of a string to title case.

```python
def char_frequency(s):
  """Calculates the frequency of each character in a string.

  Args:
    s: The input string.

  Returns:
    A dictionary where keys are characters and values are their frequencies.
  """
  frequency = {}
  for char in s:
    if char in frequency:
      frequency[char] += 1
    else:
      frequency[char] = 1
  return frequency

```

```python
def fib(n):
  if n == 0:
    return 0
  elif n == 1:
    return 1
  else:
    return fib(n-1) + fib(n-2) 
```
